create table if not exists klanten (id uuid primary key default gen_random_uuid(), klant_nr text, type text, naam text, contact text, adres text, postcode text, plaats text, telefoon text, email text, kvk text, btw text, created_at timestamptz default now());
create table if not exists projecten (id uuid primary key default gen_random_uuid(), project_nr text, factuur_nr text, naam text, klant text, status text, methode text, offerte_bedrag numeric, start_datum date, eind_datum date, betaald_datum date, created_at timestamptz default now());
create table if not exists planning (id uuid primary key default gen_random_uuid(), project text, datum date, eind_datum date, start_tijd text, eind_tijd text, notitie text, created_at timestamptz default now());
create table if not exists uren (id uuid primary key default gen_random_uuid(), datum date, klant text, project text, start_tijd text, eind_tijd text, uren numeric, tarief numeric, bedrag numeric, created_at timestamptz default now());
create table if not exists materiaal (id uuid primary key default gen_random_uuid(), datum date, project text, leverancier text, omschrijving text, bedrag numeric, pdf_naam text, created_at timestamptz default now());
create table if not exists uitgaven (id uuid primary key default gen_random_uuid(), datum date, categorie text, leverancier text, omschrijving text, bedrag numeric, btw_perc numeric, btw_bedrag numeric, created_at timestamptz default now());
